class Solution {
public:
    int getMinSwaps(string num, int k) {
        string target = num;
        while (k--) {
            nextPermutation(target);
        }
        int n = num.size();
        int swaps = 0;
        for (int i = 0; i < n; ++i) {
            if (num[i] != target[i]) {
                int j = i + 1;
                while (j < n && num[j] != target[i]) ++j;
                while (j > i) {
                    swap(num[j], num[j - 1]);
                    ++swaps;
                    --j;
                }
            }
        }
        return swaps;
    }
private:
    void nextPermutation(string& s) {
        int n = s.size();
        int i = n - 2;
        while (i >= 0 && s[i] >= s[i + 1]) --i;
        if (i < 0) return;
        int j = n - 1;
        while (s[j] <= s[i]) --j;
        swap(s[i], s[j]);
        reverse(s.begin() + i + 1, s.end());
    }
};
